import{_ as e,o as t,c as o,a3 as s}from"./chunks/framework.CVjg771q.js";const _=JSON.parse('{"title":"生肖 · 猴","description":"申猴——机智灵巧，封侯拜相","frontmatter":{"pageClass":"dao-changshi-page","aside":false,"title":"生肖 · 猴","description":"申猴——机智灵巧，封侯拜相"},"headers":[],"relativePath":"changshi/shengxiao/hou.md","filePath":"changshi/shengxiao/hou.md","lastUpdated":1779783531000}'),n={name:"changshi/shengxiao/hou.md"};function r(i,a,h,p,c,l){return t(),o("div",null,[...a[0]||(a[0]=[s('<h1 id="申猴" tabindex="-1">申猴 <a class="header-anchor" href="#申猴" aria-label="Permalink to &quot;申猴&quot;">​</a></h1><blockquote><p>地支「申」· 申时（15:00–17:00）· 五行属金 · 阴阳为阳</p></blockquote><p>猴机智好动，活灵巧变，最喜欢在申时啼叫。猴子谐音「候」，有仕途通畅、封侯拜相之意。猴子是智商最接近人类的灵长类动物，聪明机智，给人以活力和生机之感，深受人们喜爱。</p><h2 id="生肖故事-虎王的救命恩人" tabindex="-1">生肖故事：虎王的救命恩人 <a class="header-anchor" href="#生肖故事-虎王的救命恩人" aria-label="Permalink to &quot;生肖故事：虎王的救命恩人&quot;">​</a></h2><p>很久以前，老虎因镇压山兽有功被玉帝封为「百兽之王」。老虎威名远扬，动物们都敬而远之，老虎既得意又孤独。幸亏还有猴子老弟把老虎当朋友对待，每当老虎外出时，猴子就代行镇山之令——「山中无老虎，猴子称大王」由此而来。</p><p>一天虎王外出巡视，一不留神落入猎人的网中，拼命挣扎也无法脱身。恰巧被路过的猴子听到，猴子赶忙爬上树解开网绳救出了老虎。老虎脱险后，感谢猴子救命之恩。但转念一想：堂堂百兽之王竟被小小的猴子搭救，传出去岂不是灭了自己威风？</p><p>然而老虎想到自己已经是孤家寡人一个，猴子是唯一的朋友，况且人家好心救了自己，怎么能忘恩负义呢？于是老虎对猴子说：「猴老弟今日的救命之恩，今后定当全力报答。」猴子对虎王遇险的事闭口不提，虎王保全面子，关系更加密切。在玉帝选生肖时，猴子得到了虎王的力荐，便列入生肖之中。</p><p><strong>生肖习俗</strong>：每年春节期间，北京白云观庙会，人们纷纷来「摸猴」——观内藏有三只小石猴，传说摸猴可祈求平安吉祥。</p>',8)])])}const u=e(n,[["render",r]]);export{_ as __pageData,u as default};
